public final class Prefs {
    private static final String FILE = "auth_prefs";
    private static final String KEY_BIOMETRIC_ENABLED = "biometric_enabled";
    private static final String KEY_LOGGED_IN = "logged_in";

    private Prefs() {}

    public static SharedPreferences sp(Context c) {
        return c.getApplicationContext().getSharedPreferences(FILE, Context.MODE_PRIVATE);
    }

    public static boolean isBiometricEnabled(Context c) {
        return sp(c).getBoolean(KEY_BIOMETRIC_ENABLED, false);
    }

    public static void setBiometricEnabled(Context c, boolean enabled) {
        sp(c).edit().putBoolean(KEY_BIOMETRIC_ENABLED, enabled).apply();
    }

    public static boolean isLoggedIn(Context c) {
        return sp(c).getBoolean(KEY_LOGGED_IN, false);
    }

    public static void setLoggedIn(Context c, boolean loggedIn) {
        sp(c).edit().putBoolean(KEY_LOGGED_IN, loggedIn).apply();
    }

    public static void logout(Context c) {
        sp(c).edit().putBoolean(KEY_LOGGED_IN, false).apply();
    }
}

class BiometricAuth {
    interface Callback {
        void onSuccess();
        void onError(int errorCode, @NonNull CharSequence errString);
        void onFailed();
    }

    static boolean canAuthenticate(Context context) {
        BiometricManager bm = BiometricManager.from(context);
        int res = bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG
                | BiometricManager.Authenticators.BIOMETRIC_WEAK);
        return res == BiometricManager.BIOMETRIC_SUCCESS;
    }

    static void authenticate(@NonNull AppCompatActivity activity,
                             @NonNull String title,
                             @NonNull String subtitle,
                             @NonNull String negativeText,
                             @NonNull Callback callback) {

        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt.AuthenticationCallback authCallback = new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                callback.onSuccess();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                callback.onError(errorCode, errString);
            }

            @Override
            public void onAuthenticationFailed() {
                callback.onFailed();
            }
        };

        BiometricPrompt prompt = new BiometricPrompt(activity, executor, authCallback);

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setNegativeButtonText(negativeText)
                .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG
                        | BiometricManager.Authenticators.BIOMETRIC_WEAK)
                .build();

        prompt.authenticate(promptInfo);
    }
}

class LauncherActivity extends AppCompatActivity {
    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (Prefs.isLoggedIn(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        if (Prefs.isBiometricEnabled(this) && BiometricAuth.canAuthenticate(this)) {
            BiometricAuth.authenticate(
                    this,
                    "Unlock",
                    "Authenticate to continue",
                    "Use password",
                    new BiometricAuth.Callback() {
                        @Override
                        public void onSuccess() {
                            Prefs.setLoggedIn(LauncherActivity.this, true);
                            startActivity(new Intent(LauncherActivity.this, HomeActivity.class));
                            finish();
                        }

                        @Override
                        public void onError(int errorCode, @NonNull CharSequence errString) {
                            startActivity(new Intent(LauncherActivity.this, LoginActivity.class));
                            finish();
                        }

                        @Override
                        public void onFailed() {
                        }
                    }
            );
        } else {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        }
    }
}

class LoginActivity extends AppCompatActivity {

    private EditText usernameEt;
    private EditText passwordEt;
    private CheckBox enableBiometricCb;
    private TextView statusTv;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(48, 48, 48, 48);
        root.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT));

        TextView title = new TextView(this);
        title.setText("Login");
        title.setTextSize(22f);
        title.setGravity(Gravity.START);

        usernameEt = new EditText(this);
        usernameEt.setHint("Username");

        passwordEt = new EditText(this);
        passwordEt.setHint("Password");
        passwordEt.setInputType(InputType.TYPE_CLASS_TEXT | InputType.TYPE_TEXT_VARIATION_PASSWORD);

        enableBiometricCb = new CheckBox(this);
        enableBiometricCb.setText("Enable biometric login");
        enableBiometricCb.setChecked(Prefs.isBiometricEnabled(this));

        statusTv = new TextView(this);

        Button loginBtn = new Button(this);
        loginBtn.setText("Login");

        Button biometricBtn = new Button(this);
        biometricBtn.setText("Use fingerprint");
        biometricBtn.setEnabled(Prefs.isBiometricEnabled(this) && BiometricAuth.canAuthenticate(this));

        root.addView(title);
        root.addView(usernameEt);
        root.addView(passwordEt);
        root.addView(enableBiometricCb);
        root.addView(loginBtn);
        root.addView(biometricBtn);
        root.addView(statusTv);

        setContentView(root);

        enableBiometricCb.setOnCheckedChangeListener((buttonView, isChecked) -> {
            if (isChecked && !BiometricAuth.canAuthenticate(this)) {
                statusTv.setText("Biometric not available on this device.");
                enableBiometricCb.setChecked(false);
                Prefs.setBiometricEnabled(this, false);
                biometricBtn.setEnabled(false);
                return;
            }
            Prefs.setBiometricEnabled(this, isChecked);
            biometricBtn.setEnabled(isChecked && BiometricAuth.canAuthenticate(this));
            statusTv.setText("");
        });

        loginBtn.setOnClickListener(v -> {
            String u = usernameEt.getText() != null ? usernameEt.getText().toString() : "";
            String p = passwordEt.getText() != null ? passwordEt.getText().toString() : "";

            if (u.trim().isEmpty() || p.isEmpty()) {
                statusTv.setText("Enter username and password.");
                return;
            }

            Prefs.setLoggedIn(this, true);

            if (enableBiometricCb.isChecked()) {
                if (!BiometricAuth.canAuthenticate(this)) {
                    statusTv.setText("Biometric not available on this device.");
                    Prefs.setBiometricEnabled(this, false);
                    enableBiometricCb.setChecked(false);
                } else {
                    Prefs.setBiometricEnabled(this, true);
                }
            }

            startActivity(new Intent(this, HomeActivity.class));
            finish();
        });

        biometricBtn.setOnClickListener(v -> {
            if (!Prefs.isBiometricEnabled(this)) {
                statusTv.setText("Enable biometric login first.");
                return;
            }
            if (!BiometricAuth.canAuthenticate(this)) {
                statusTv.setText("Biometric not available on this device.");
                return;
            }

            BiometricAuth.authenticate(
                    this,
                    "Unlock",
                    "Authenticate to login",
                    "Use password",
                    new BiometricAuth.Callback() {
                        @Override
                        public void onSuccess() {
                            Prefs.setLoggedIn(LoginActivity.this, true);
                            startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                            finish();
                        }

                        @Override
                        public void onError(int errorCode, @NonNull CharSequence errString) {
                            statusTv.setText(errString);
                        }

                        @Override
                        public void onFailed() {
                            statusTv.setText("Not recognized. Try again.");
                        }
                    }
            );
        });
    }
}

